export function getEcommerceCatalogMetadataText(language: string, englishText: string): string | null {
  const resolved = resolveLanguage(language);
  if (!resolved) return null;
  const key = String(englishText ?? "");
  return (
    ECOMMERCE_CATALOG_METADATA_QA_OVERRIDES[resolved]?.[key] ??
    ECOMMERCE_CATALOG_METADATA_I18N_MAPS[resolved][key] ??
    null
  );
}
